// ==================== 工具函数 ====================

/** 获取单词总数 */
function getTotalCount() {
  return getWords().length
}

/** 获取全部单词 */
function getAllWords() {
  return getWords()
}

/** 按字母分组索引（A-Z） */
function getAlphabetGroups() {
  const groups = {}
  for (let i = 0; i < 26; i++) {
    const letter = String.fromCharCode(65 + i)
    groups[letter] = []
  }
  for (const w of getWords()) {
    const first = w.en[0].toUpperCase()
    if (groups[first]) {
      groups[first].push(w)
    } else {
      // Non-letter starts go to '#'
      if (!groups['#']) groups['#'] = []
      groups['#'].push(w)
    }
  }
  return groups
}

/** 获取字母分组列表（含词数） */
function getAlphabetGroupList() {
  const groups = []
  let count = 0
  for (let i = 0; i < 26; i++) {
    const letter = String.fromCharCode(65 + i)
    groups.push({ key: letter, name: letter, count: 0 })
  }
  for (const w of getWords()) {
    const first = w.en[0].toUpperCase()
    const idx = first.charCodeAt(0) - 65
    if (idx >= 0 && idx < 26) {
      groups[idx].count++
      count++
    }
  }
  return groups.filter(g => g.count > 0)
}

/** 按字母分组获取单词 */
function getWordsByAlphabet(letter) {
  return getWords().filter(w => w.en[0].toUpperCase() === letter.toUpperCase())
}

/** 随机抽取指定数量的单词 */
const GROUP_SIZE = 30
const TOTAL_GROUPS = Math.ceil(getWords().length / GROUP_SIZE)

/** 获取总组数 */
function getTotalGroups() {
  return TOTAL_GROUPS
}

/** 获取每组词数 */
function getGroupSize() {
  return GROUP_SIZE
}

/** 获取指定组（从 0 开始） */
function getGroup(index) {
  const start = index * GROUP_SIZE
  const end = Math.min(start + GROUP_SIZE, getWords().length)
  return getWords().slice(start, end)
}

/** 获取当前组的信息 */
function getGroupInfo(index) {
  const words = getGroup(index)
  return {
    index,
    total: TOTAL_GROUPS,
    start: index * GROUP_SIZE + 1,
    end: index * GROUP_SIZE + words.length,
    count: words.length,
    words
  }
}

function getRandomWords(count) {
  const shuffled = [...getWords()].sort(() => Math.random() - 0.5)
  return shuffled.slice(0, Math.min(count, shuffled.length))
}

/** 搜索单词（按英文或中文关键词，区分大小写不敏感） */
function searchWords(keyword) {
  if (!keyword) return []
  const kw = keyword.toLowerCase()
  return getWords().filter(w =>
    w.en.toLowerCase().includes(kw) ||
    w.zh.includes(kw)
  )
}

module.exports = {
  getWords,
  getTotalCount,
  getAllWords,
  getAlphabetGroups,
  getAlphabetGroupList,
  getWordsByAlphabet,
  getTotalGroups,
  getGroupSize,
  getGroup,
  getGroupInfo,
  getRandomWords,
  searchWords
}
